import React, { useEffect } from 'react';
import { AsyncStorage, NetInfo } from 'react-native';
import { createLogger } from 'redux-logger';

const logger = createLogger({
  predicate: (getState, action) => true,
  level: process.env.NODE_ENV !== 'production' ? 'debug' : 'error',
  collapsed: false,
  duration: true,
  timestamp: true
});

const requestLogger = {
  logRequest(url, options) {
    console.log('Network Request:', url, options);
  },
  logResponse(url, response) {
    console.log('Network Response:', url, response);
  }
};

NetInfo.addEventListener('connectionChange', (networkState) => {
  console.debug('Network Change:', networkState);
});

const authenticationTokenLogger = async () => {
  try {
    const token = await AsyncStorage.getItem('authToken');
    console.log('Authentication Token:', token);
  } catch (error) {
    console.error('Failed to get auth token:', error);
  }
};

const userDataLogger = async () => {
  try {
    const userData = await AsyncStorage.getItem('userData');
    console.log('User Data:', JSON.parse(userData));
  } catch (error) {
    console.error('Failed to get user data:', error);
  }
};

export const useDebuggingModule = () => {
  useEffect(() => {
    authenticationTokenLogger();
    userDataLogger();

    return () => {
      NetInfo.removeEventListener('connectionChange');
    };
  }, []);

  return { logger, requestLogger };
};